@namespace sv_344caa6333d94a0ca3f8bba2c4a168d5.Components.Catalog

<div class="card product-card h-100" @onclick="HandleCardClick" role="button">
    <div class="product-image-placeholder d-flex align-items-center justify-content-center bg-light"
         style="height: 180px;">
        <span class="text-muted">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title text-truncate" title="@Product.Name">@Product.Name</h6>
        <p class="card-text fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <p class="card-text mb-2">
            <span class="text-warning">@StarRating</span>
        </p>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public Product Product { get; set; } = default!;
    [Parameter] public EventCallback<Product> OnSelected { get; set; }
    [Parameter] public EventCallback<Product> OnAddToCart { get; set; }

    private string StarRating
    {
        get
        {
            int filled = (int)Math.Round(Product.Rating);
            return new string('★', filled) + new string('☆', 5 - filled);
        }
    }

    private async Task HandleCardClick() => await OnSelected.InvokeAsync(Product);
    private async Task HandleAddToCart() => await OnAddToCart.InvokeAsync(Product);
}

@namespace sv_344caa6333d94a0ca3f8bba2c4a168d5.Components.Catalog

<div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
    @foreach (var product in Products)
    {
        <div class="col">
            <ProductCard Product="product"
                         OnSelected="OnProductSelected"
                         OnAddToCart="OnAddToCart" />
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Product> Products { get; set; } = [];
    [Parameter] public EventCallback<Product> OnProductSelected { get; set; }
    [Parameter] public EventCallback<Product> OnAddToCart { get; set; }
}

@namespace sv_344caa6333d94a0ca3f8bba2c4a168d5.Components.Catalog

<div class="p-3 border rounded bg-light">
    <h5 class="mb-3">Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-semibold">Categories</label>
        @foreach (var category in Categories)
        {
            <div class="form-check">
                <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                       checked="@_selectedCategories.Contains(category)"
                       @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                <label class="form-check-label" for="@($"cat-{category}")">@category</label>
            </div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Price Range</label>
        <div class="d-flex gap-2 align-items-center">
            <input type="number" class="form-control form-control-sm" placeholder="Min"
                   value="@_minPrice" @onchange="e => _minPrice = ParseDecimal(e.Value)" />
            <span>–</span>
            <input type="number" class="form-control form-control-sm" placeholder="Max"
                   value="@_maxPrice" @onchange="e => _maxPrice = ParseDecimal(e.Value)" />
        </div>
    </div>

    <div class="form-check mb-3">
        <input class="form-check-input" type="checkbox" id="inStockOnly"
               checked="@_inStockOnly"
               @onchange="e => _inStockOnly = (bool)e.Value!" />
        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<string> Categories { get; set; } = [];
    [Parameter] public EventCallback<ProductFilter> OnApply { get; set; }
    [Parameter] public EventCallback OnClear { get; set; }

    private HashSet<string> _selectedCategories = [];
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked) _selectedCategories.Add(category);
        else _selectedCategories.Remove(category);
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString())) return null;
        return decimal.TryParse(value.ToString(), out var d) ? d : null;
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );
        await OnApply.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnClear.InvokeAsync();
    }
}

@namespace sv_344caa6333d94a0ca3f8bba2c4a168d5.Components.Catalog

<div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
    <div>
        <label class="form-label mb-0 me-2 fw-semibold">Sort by:</label>
        <select class="form-select form-select-sm d-inline-block w-auto"
                value="@SortBy"
                @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A-Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>

    <span class="text-muted">
        @if (TotalCount > 0)
        {
            var start = (Page - 1) * PageSize + 1;
            var end = Math.Min(Page * PageSize, TotalCount);
            <text>Showing @start–@end of @TotalCount products</text>
        }
        else
        {
            <text>No products found</text>
        }
    </span>
</div>

@code {
    [Parameter] public string SortBy { get; set; } = "price_asc";
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public int Page { get; set; } = 1;
    [Parameter] public int PageSize { get; set; } = 12;
    [Parameter] public EventCallback<string> OnSortChanged { get; set; }

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}

@namespace sv_344caa6333d94a0ca3f8bba2c4a168d5.Components.Catalog

@if (TotalPages > 1)
{
    <nav aria-label="Product pagination" class="mt-4">
        <ul class="pagination justify-content-center">
            <li class="page-item @(Page <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(Page - 1)" disabled="@(Page <= 1)">
                    Previous
                </button>
            </li>

            @foreach (var p in PageNumbers)
            {
                <li class="page-item @(p == Page ? "active" : "")">
                    <button class="page-link" @onclick="() => GoToPage(p)">@p</button>
                </li>
            }

            <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(Page + 1)" disabled="@(Page >= TotalPages)">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter] public int Page { get; set; } = 1;
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public int PageSize { get; set; } = 12;
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private int TotalPages => (int)Math.Ceiling((double)TotalCount / PageSize);

    private IEnumerable<int> PageNumbers
    {
        get
        {
            // Show up to 7 page numbers centered around current page
            int start = Math.Max(1, Page - 3);
            int end = Math.Min(TotalPages, start + 6);
            start = Math.Max(1, end - 6);
            return Enumerable.Range(start, end - start + 1);
        }
    }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != Page)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}

@page "/catalog"
@using sv_344caa6333d94a0ca3f8bba2c4a168d5.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-link" @onclick="ReloadAsync">Try Again</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-3">
            <CatalogSidebar Categories="_categories"
                            OnApply="HandleFilterApplied"
                            OnClear="HandleFilterCleared" />
        </div>

        <div class="col-md-9">
            @if (_loading)
            {
                <div class="d-flex justify-content-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                </div>
            }
            else if (_result is not null && _result.Items.Count == 0)
            {
                <div class="text-center py-5">
                    <p class="text-muted fs-5">No products match your filters.</p>
                    <button class="btn btn-outline-primary" @onclick="HandleFilterCleared">
                        Clear Filters
                    </button>
                </div>
            }
            else if (_result is not null)
            {
                <CatalogToolbar SortBy="@_sortBy"
                                TotalCount="_result.TotalCount"
                                Page="_result.Page"
                                PageSize="_result.PageSize"
                                OnSortChanged="HandleSortChanged" />

                <ProductGrid Products="_result.Items"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                <CatalogPagination Page="_result.Page"
                                   TotalCount="_result.TotalCount"
                                   PageSize="_result.PageSize"
                                   OnPageChanged="HandlePageChanged" />
            }
        </div>
    </div>
}

@code {
    /// <summary>
    /// Raised when a product card is clicked for navigation to the detail page.
    /// </summary>
    [Parameter] public EventCallback<Product> OnProductSelected { get; set; }

    private List<string> _categories = [];
    private PagedResult<Product>? _result;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _page = 1;
    private int _pageSize = 12;
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        await ReloadAsync();
    }

    private async Task ReloadAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _page, _pageSize);
            await Task.WhenAll(categoriesTask, searchTask);

            _categories = categoriesTask.Result;
            _result = searchTask.Result;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            _result = await ProductService.SearchAsync(_filter, _sortBy, _page, _pageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _page = 1;
        await SearchAsync();
    }

    private async Task HandleFilterCleared()
    {
        _filter = new ProductFilter(null, null, null, false);
        _page = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _page = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _page = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder — wire to a cart service when available
        return Task.CompletedTask;
    }
}

