@namespace sv_344caa6333d94a0ca3f8bba2c4a168d5.Components.Catalog

<div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
    <div>
        <label class="form-label mb-0 me-2 fw-semibold">Sort by:</label>
        <select class="form-select form-select-sm d-inline-block w-auto"
                value="@SortBy"
                @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A-Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>

    <span class="text-muted">
        @if (TotalCount > 0)
        {
            var start = (Page - 1) * PageSize + 1;
            var end = Math.Min(Page * PageSize, TotalCount);
            <text>Showing @start–@end of @TotalCount products</text>
        }
        else
        {
            <text>No products found</text>
        }
    </span>
</div>

@code {
    [Parameter] public string SortBy { get; set; } = "price_asc";
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public int Page { get; set; } = 1;
    [Parameter] public int PageSize { get; set; } = 12;
    [Parameter] public EventCallback<string> OnSortChanged { get; set; }

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}

